import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, MyDialog } from '../../../includes';
import { TableCell, Button, IconButton } from '@material-ui/core';
import { HIRButtonTable } from '../../Includes';
import { appActions } from '../../../../actions';
import { hirUserActions } from '../actions';
import { Done, Edit } from '@material-ui/icons';
import { HIRUserForm } from '../HIRUserForm';
import { hirUtil } from '../../utils';


const style = theme => ({
    root: {
    },
    cell : {
        fontSize : 11, 
        padding : 5,
    },
    activateBtn : {

    },
    suspendBtn : {

    }
})
class _HIRUserList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            user : null,
            editDialog : false,
        }
    }
    
    activateUserWarning = user => ()=>{
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are sure you want to activate " + user.myProfile.lastName + "?",
            [<Button 
                onClick={this.activateUser(user._id)} 
                key={"active"+user._id}>Activate</Button>]
        )(dispatch);
    }
    activateUser = userId => () => {
        const {dispatch, actionCallback} = this.props;
        appActions.closeSnackDialog()(dispatch);
        hirUserActions.activateUser(userId, done => {
            if(done){
                if(actionCallback) actionCallback();
            }
        })(dispatch);
    }
    suspendUserWarning = user => ()=>{
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are sure you want to suspend " + user.myProfile.lastName + "?",
            [<Button 
                onClick={this.suspendUser(user._id)} 
                key={"active"+user._id}>Suspend</Button>]
        )(dispatch);
    }
    suspendUser = userId => () => {
        const {dispatch, actionCallback} = this.props;
        appActions.closeSnackDialog()(dispatch);
        hirUserActions.suspendUser(userId, (done)=>{
            if(done){
                if(actionCallback) actionCallback();
            }
        })(dispatch);
    }
    archiveUserWarning = user => ()=>{
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "This user won't have access to this application and won't be enlisted again.\nAre sure you want to archive " + user.myProfile.lastName + "?",
            [<Button 
                onClick={this.archiveUser(user._id)} 
                key={"active"+user._id}>Archive</Button>]
        )(dispatch);
    }
    archiveUser = userId => () => {
        const {dispatch, actionCallback} = this.props;
        appActions.closeSnackDialog()(dispatch);
        hirUserActions.archiveUser(userId, done => {
            if(done){
                if(actionCallback) actionCallback();
            }
        })(dispatch);
    }
    showEditDialog = user => () => {
        delete user.myProfile.password;
        this.setState({editDialog : true, user})
    }
    cellMapFormat = ({row, cellMap}) => {
        const {classes} = this.props;
        const {myProfile} = row;
        switch(cellMap){
            case "action" : return <TableCell className={classes.cell}>
                {myProfile.status === "s" ? 
                    <HIRButtonTable
                        title="activate"
                        onClickCallback={this.activateUserWarning(row)}
                        classes={{btn : classes.activateBtn}}/>
                        :
                    <HIRButtonTable
                        title="suspend"
                        onClickCallback={this.suspendUserWarning(row)}
                        type="secondary"
                        classes={{btn : classes.suspendBtn}}/>
                }
                <HIRButtonTable
                        title="archive"
                        onClickCallback={this.archiveUserWarning(row)}
                        type="highlight"
                        classes={{btn : classes.suspendBtn}}/>
                <IconButton onClick={this.showEditDialog(row)}>
                    <Edit/>
                </IconButton>
            </TableCell>
            case "email" : return <TableCell className={classes.cell}>
                {myProfile.email}
            </TableCell>
            case "phone" : return <TableCell className={classes.cell}>
                {myProfile.phone}
            </TableCell>
            case "userName" : return <TableCell className={classes.cell}>
                {myProfile.userName}
            </TableCell>
            case "name" : return <TableCell className={classes.cell}>
                {myProfile.lastName}, {myProfile.firstName}
            </TableCell> 
            case "_id" : return <TableCell className={classes.cell}>
                {String(row[cellMap]).padStart(6, "0")}
            </TableCell>
            case "privilege" : return <TableCell className={classes.cell}>
                {myProfile[cellMap] === 11 && <Done style={{color : hirUtil.getTheme().secondary}}/>}
            </TableCell>
            default : return <TableCell className={classes.cell}>
                {myProfile[cellMap]}
            </TableCell>
        }
    }
    updateUser(data, context){
        const {dispatch} = this.props;
        const {user} = this.state;
        hirUserActions.updateProfile(user._id, data, (done)=>{
            if(context) context.setState({loading : false});
            if(done){
                this.setState({editDialog : false});
                hirUserActions.getUsers()(dispatch);
            }
        })(dispatch);
    }
    render() {
        const {classes} = this.props;
        const {editDialog, user } = this.state;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["ID", "Name", "Username", "Phone", "email", "Admin", "Action"]}
                    dataMap={["_id", "name", "userName", "phone", "email", "privilege", "action"]}
                    CellMap={this.cellMapFormat.bind(this)}
                    {...this.props.tableProps}
                    />
                <MyDialog
                    open={editDialog}
                    close={()=>this.setState({editDialog :false})}>
                        <HIRUserForm
                            data={user ? {...user.myProfile, privilege : user.myProfile.privilege === 11 ? ["admin"] : ""} : {}}
                            editMode
                            editUser={this.updateUser.bind(this)}/>
                    </MyDialog>
            </div>
        );
    }
}


_HIRUserList.propTypes = {
    classes : PropTypes.object.isRequired,
    tableProps : PropTypes.shape(MyTable.propTypes),
    actionCallback : PropTypes.func,
};
const mapStateToProps = state => ({
    state
})


export const HIRUserList = connect(mapStateToProps)(withStyles(style)(_HIRUserList));
export {HIRUserList as default}