import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {connect} from 'react-redux';
import { FormDisplay } from '../../../includes';
import { HIRButton } from '../../Includes/Buttons';
import { CircularProgress } from '@material-ui/core';
import { getFormDisplayData } from '../../../includes/Forms/FormDisplay/functions';
import { appActions, alertAction } from '../../../../actions';
const style = theme => ({
    root: {
        
    }
})
class _HIRUserForm extends Component {
    constructor(props) {
        super(props);
        this.state = {
            loading : false,
        }
        const required = true;
        this.formConfig = [
            {name : "lastName", label :"Last Name", placeholder : "Last name", required},
            {name : "firstName", label :"First Name", placeholder : "First name", required},
            {name : "email", label :"Email", placeholder : "Email", required},
            {name : "phone", label :"Phone", placeholder : "Phone", required},
            {name : "userName", label : "Username", placeholder :"Username", required},
            {name : "password", label :"Password", placeholder : "Password", type : "password", required},
            {name : "cpassword", label :"Confirm Password", placeholder : "Password", type : "password", required},
            {name : "privilege", "Label" : "Admin", type : "check", options : [
                {_id : "admin", name : "Admin"}
            ], required},
        ]
    }
    onClick(){
        this.setState({loading : true});
        const {dispatch, createUser, editMode, editUser} = this.props;
        const data = getFormDisplayData(this.newUserFormContext, (name, value)=>{
            if(name !== "privilege" && (!String(value).trim() || String(value).trim() === "")){
                appActions.showSnackbar(
                    alertAction.error("Empty field, Please complete the required fields")
                )(dispatch);
                return false;
            }
            return true;
        })();
        if(data.privilege) data.privilege = data.privilege[0];
        if(data.password !== data.cpassword){
            appActions.showSnackbar(
                alertAction.error("Password mismatch!")
            )(dispatch);
            return;
        }
        if(String(data.password).length < 6){
            appActions.showSnackbar(
                alertAction.error("Password is too short!")
            )(dispatch);
            return;
        }
        if(data){
            delete data.cpassword;
            if(createUser) createUser(data, this);
            else if (editUser) editUser(data, this);
        }else this.setState({loading : false});
    }
    createUserBtn = ({loading}) => () => {
        const {editMode} = this.props;
        return <HIRButton 
            disabled={loading}
            onClick={this.onClick.bind(this)}>
            {loading && 
                <CircularProgress 
                    style={{width : 30, height : 30}} 
                    color="secondary"/>
            } {editMode ? "Edit User" : "Create User"}
        </HIRButton>
    }
    render() {
        const {classes, editMode, data} = this.props;
        const {loading } = this.state;
        return (
            <div className={classes.root}>
                <FormDisplay
                    getContext={context=>this.newUserFormContext = context}
                    header="New User"
                    formName="newUserForm"
                    formConfig={this.formConfig}
                    formData={data}
                    footer={this.createUserBtn({loading})}
                    />
            </div>
        );
    }
}
_HIRUserForm.propTypes = {
    classes : PropTypes.object.isRequired,
    createUser : PropTypes.func,
    data : PropTypes.object,
    editMode : PropTypes.bool,
    editUser : PropTypes.func,
};
export const HIRUserForm = connect()(withStyles(style)(_HIRUserForm));